import React, { useEffect, useState } from 'react';
import { supabase } from '../services/supabaseClient';
import { User, Shield, Trash2, Edit, Save, X, Loader2 } from 'lucide-react';

const Perfil = () => {
  const [perfil, setPerfil] = useState(null);
  const [usuarios, setUsuarios] = useState([]);
  const [loading, setLoading] = useState(true);
  const [editandoNome, setEditandoNome] = useState(false);
  const [novoNome, setNovoNome] = useState('');

  useEffect(() => {
    carregarDados();
  }, []);

  const carregarDados = async () => {
    try {
      setLoading(true);
      const { data: { user } } = await supabase.auth.getUser();

      if (!user) return;

      // Buscar perfil do usuário logado
      const { data: meuPerfil, error } = await supabase
        .from('profiles')
        .select('*')
        .eq('id', user.id)
        .maybeSingle(); // Usamos maybeSingle para não quebrar se não achar

      if (error) throw error;

      if (meuPerfil) {
        setPerfil(meuPerfil);
        setNovoNome(meuPerfil.nome || '');

        // Se for proprietário, busca a lista completa
        if (meuPerfil.tipo_usuario === 'proprietario') {
          const { data: todos } = await supabase
            .from('profiles')
            .select('*')
            .order('nome', { ascending: true });
          setUsuarios(todos || []);
        }
      }
    } catch (err) {
      console.error("Erro ao carregar perfil:", err);
    } finally {
      setLoading(false);
    }
  };

  // Se estiver carregando, mostra um spinner
  if (loading) {
    return (
      <div style={{ display: 'flex', justifyContent: 'center', padding: '50px' }}>
        <Loader2 className="animate-spin" size={32} color="#4361ee" />
      </div>
    );
  }

  // Se o perfil não foi encontrado no banco (Raro após o SQL que fizemos)
  if (!perfil) {
    return <div style={{ padding: '20px' }}>Perfil não encontrado. Tente fazer login novamente.</div>;
  }

  return (
    <div style={{ padding: '30px', maxWidth: '800px', margin: '0 auto' }}>
      <h2 style={{ display: 'flex', alignItems: 'center', gap: '10px', color: '#0f172a' }}>
        <User size={24} /> Meu Perfil
      </h2>

      <div style={cardStyle}>
        <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center' }}>
          <div>
            {editandoNome ? (
              <div style={{ display: 'flex', gap: '10px' }}>
                <input 
                  value={novoNome} 
                  onChange={(e) => setNovoNome(e.target.value)}
                  style={inputStyle}
                />
                <button onClick={() => { /* sua função de update */ }} style={saveBtnStyle}><Save size={18}/></button>
                <button onClick={() => setEditandoNome(false)} style={cancelBtnStyle}><X size={18}/></button>
              </div>
            ) : (
              <h3 style={{ margin: 0 }}>
                {perfil.nome || 'Usuário sem nome'} 
                <Edit size={16} onClick={() => setEditandoNome(true)} style={{cursor:'pointer', marginLeft: '10px', color:'#64748b'}}/>
              </h3>
            )}
            <p style={{ color: '#64748b', fontSize: '0.9rem', margin: '5px 0', display: 'flex', alignItems: 'center', gap: '5px' }}>
              <Shield size={14} /> {perfil.tipo_usuario?.toUpperCase() || 'COMUM'}
            </p>
          </div>
        </div>
      </div>

      {/* ÁREA DO PROPRIETÁRIO */}
      {perfil.tipo_usuario === 'proprietario' && usuarios.length > 0 && (
        <div style={{ marginTop: '40px' }}>
          <h3 style={{ color: '#0f172a', marginBottom: '15px' }}>Gestão de Usuários</h3>
          <div style={{ display: 'grid', gap: '12px' }}>
            {usuarios.map(u => (
              <div key={u.id} style={userItemStyle}>
                <div style={{ display: 'flex', flexDirection: 'column' }}>
                  <span style={{ fontWeight: 600 }}>{u.nome || 'Sem nome'}</span>
                  <span style={{ fontSize: '0.8rem', color: '#64748b' }}>{u.email}</span>
                </div>
                <div style={{ display: 'flex', gap: '10px' }}>
                  <span style={badgeStyle(u.tipo_usuario)}>{u.tipo_usuario}</span>
                  <button onClick={() => {/* função de deletar */}} style={deleteBtnStyle}>
                    <Trash2 size={16} />
                  </button>
                </div>
              </div>
            ))}
          </div>
        </div>
      )}
    </div>
  );
};

// Estilos
const cardStyle = { backgroundColor: '#fff', padding: '24px', borderRadius: '16px', boxShadow: '0 4px 6px -1px rgba(0,0,0,0.1)', marginTop: '20px' };
const userItemStyle = { display: 'flex', justifyContent: 'space-between', alignItems: 'center', padding: '16px', backgroundColor: '#fff', borderRadius: '12px', border: '1px solid #e2e8f0' };
const inputStyle = { padding: '8px', borderRadius: '8px', border: '1px solid #cbd5e1', outline: 'none' };
const saveBtnStyle = { background: '#22c55e', color: '#fff', border: 'none', borderRadius: '8px', padding: '8px', cursor: 'pointer' };
const cancelBtnStyle = { background: '#ef4444', color: '#fff', border: 'none', borderRadius: '8px', padding: '8px', cursor: 'pointer' };
const deleteBtnStyle = { background: 'none', border: 'none', color: '#ef4444', cursor: 'pointer', display: 'flex', alignItems: 'center' };
const badgeStyle = (tipo) => ({
    padding: '4px 10px',
    borderRadius: '20px',
    fontSize: '0.75rem',
    fontWeight: 700,
    backgroundColor: tipo === 'proprietario' ? '#4361ee20' : '#f1f5f9',
    color: tipo === 'proprietario' ? '#4361ee' : '#64748b',
    textTransform: 'uppercase'
});

export default Perfil;
